     1→// SPDX-License-Identifier: MIT
     2→pragma solidity ^0.8.24;
     3→
     4→import "forge-std/Test.sol";
     5→import {AgentMicrolending, ISelfAgentRegistry} from "../src/AgentMicrolending.sol";
     6→import {ERC20} from "@openzeppelin/contracts/token/ERC20/ERC20.sol";
     7→
     8→/// @dev Minimal mock USDC (6 decimals) for testing.
     9→contract MockUSDC is ERC20 {
    10→    constructor() ERC20("USD Coin", "USDC") {}
    11→
    12→    function decimals() public pure override returns (uint8) {
    13→        return 6;
    14→    }
    15→
    16→    function mint(address to, uint256 amount) external {
    17→        _mint(to, amount);
    18→    }
    19→}
    20→
    21→/// @dev Mock Self Agent Registry for testing identity verification.
    22→contract MockSelfRegistry is ISelfAgentRegistry {
    23→    mapping(uint256 => address) private _wallets;
    24→    mapping(uint256 => bool) private _humanProofs;
    25→
    26→    function setAgentWallet(uint256 agentId, address wallet) external {
    27→        _wallets[agentId] = wallet;
    28→    }
    29→
    30→    function setHumanProof(uint256 agentId, bool hasProof) external {
    31→        _humanProofs[agentId] = hasProof;
    32→    }
    33→
    34→    function getAgentWallet(uint256 agentId) external view override returns (address) {
    35→        return _wallets[agentId];
    36→    }
    37→
    38→    function hasHumanProof(uint256 agentId) external view override returns (bool) {
    39→        return _humanProofs[agentId];
    40→    }
    41→}
    42→
    43→contract AgentMicrolendingTest is Test {
    44→    AgentMicrolending lending;
    45→    MockUSDC usdc;
    46→    MockSelfRegistry registry;
    47→
    48→    address borrower = makeAddr("borrower");
    49→    address lender = makeAddr("lender");
    50→    address stranger = makeAddr("stranger");
    51→
    52→    // Agent ID used for the borrower in most tests
    53→    uint256 constant BORROWER_AGENT_ID = 1;
    54→
    55→    // 1 USDC = 1e6
    56→    uint256 constant ONE_USDC = 1e6;
    57→
    58→    function setUp() public {
    59→        usdc = new MockUSDC();
    60→        registry = new MockSelfRegistry();
    61→        lending = new AgentMicrolending(address(usdc), address(registry));
    62→
    63→        // Register borrower as a verified agent
    64→        registry.setAgentWallet(BORROWER_AGENT_ID, borrower);
    65→        registry.setHumanProof(BORROWER_AGENT_ID, true);
    66→
    67→        // Mint USDC to test accounts
    68→        usdc.mint(borrower, 1000 * ONE_USDC);
    69→        usdc.mint(lender, 1000 * ONE_USDC);
    70→        usdc.mint(stranger, 1000 * ONE_USDC);
    71→
    72→        // Approve lending contract to spend tokens
    73→        vm.prank(borrower);
    74→        usdc.approve(address(lending), type(uint256).max);
    75→        vm.prank(lender);
    76→        usdc.approve(address(lending), type(uint256).max);
    77→        vm.prank(stranger);
    78→        usdc.approve(address(lending), type(uint256).max);
    79→    }
    80→
    81→    // ════════════════════════════════════════════
    82→    //  Constructor
    83→    // ════════════════════════════════════════════
    84→
    85→    function test_constructorSetsToken() public view {
    86→        assertEq(address(lending.token()), address(usdc));
    87→    }
    88→
    89→    function test_constructorSetsSelfRegistry() public view {
    90→        assertEq(address(lending.selfRegistry()), address(registry));
    91→    }
    92→
    93→    function test_constructorZeroTokenReverts() public {
    94→        vm.expectRevert(AgentMicrolending.ZeroAddress.selector);
    95→        new AgentMicrolending(address(0), address(registry));
    96→    }
    97→
    98→    function test_constructorZeroRegistryReverts() public {
    99→        vm.expectRevert(AgentMicrolending.ZeroAddress.selector);
   100→        new AgentMicrolending(address(usdc), address(0));
   101→    }
   102→
   103→    // ════════════════════════════════════════════
   104→    //  Self identity verification
   105→    // ════════════════════════════════════════════
   106→
   107→    function test_createLoanRevertsIfNotVerifiedAgent() public {
   108→        // stranger has no agent ID registered
   109→        vm.prank(stranger);
   110→        vm.expectRevert(AgentMicrolending.NotVerifiedAgent.selector);
   111→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, 999);
   112→    }
   113→
   114→    function test_createLoanRevertsIfWrongAgentId() public {
   115→        // agentId 42 is linked to a different wallet, not borrower
   116→        registry.setAgentWallet(42, makeAddr("someoneElse"));
   117→        registry.setHumanProof(42, true);
   118→
   119→        vm.prank(borrower);
   120→        vm.expectRevert(AgentMicrolending.NotVerifiedAgent.selector);
   121→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, 42);
   122→    }
   123→
   124→    function test_createLoanRevertsIfNoHumanProof() public {
   125→        // Wallet is linked but human proof is missing
   126→        uint256 noProofAgentId = 77;
   127→        registry.setAgentWallet(noProofAgentId, borrower);
   128→        registry.setHumanProof(noProofAgentId, false);
   129→
   130→        vm.prank(borrower);
   131→        vm.expectRevert(AgentMicrolending.NotVerifiedAgent.selector);
   132→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, noProofAgentId);
   133→    }
   134→
   135→    function test_createLoanRevertsIfWalletLinkedButNoProof() public {
   136→        // Agent wallet matches msg.sender but hasHumanProof returns false
   137→        registry.setHumanProof(BORROWER_AGENT_ID, false);
   138→
   139→        vm.prank(borrower);
   140→        vm.expectRevert(AgentMicrolending.NotVerifiedAgent.selector);
   141→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, BORROWER_AGENT_ID);
   142→    }
   143→
   144→    function test_createLoanSucceedsWithVerifiedAgent() public {
   145→        vm.prank(borrower);
   146→        uint256 loanId = lending.createLoanRequest(
   147→            100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, BORROWER_AGENT_ID
   148→        );
   149→        assertEq(loanId, 0);
   150→        assertEq(lending.totalLoans(), 1);
   151→    }
   152→
   153→    // ════════════════════════════════════════════
   154→    //  Loan creation
   155→    // ════════════════════════════════════════════
   156→
   157→    function test_createLoanRequest() public {
   158→        uint256 deadline = block.timestamp + 30 days;
   159→
   160→        vm.prank(borrower);
   161→        uint256 loanId = lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, deadline, lender, BORROWER_AGENT_ID);
   162→
   163→        assertEq(loanId, 0);
   164→        assertEq(lending.totalLoans(), 1);
   165→
   166→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(0);
   167→        assertEq(loan.id, 0);
   168→        assertEq(loan.borrower, borrower);
   169→        assertEq(loan.lender, lender);
   170→        assertEq(loan.actualLender, address(0));
   171→        assertEq(loan.amount, 100 * ONE_USDC);
   172→        assertEq(loan.repayAmount, 110 * ONE_USDC);
   173→        assertEq(loan.deadline, deadline);
   174→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Open));
   175→    }
   176→
   177→    function test_createLoanRequestOpenToAnyone() public {
   178→        uint256 deadline = block.timestamp + 30 days;
   179→
   180→        vm.prank(borrower);
   181→        uint256 loanId =
   182→            lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, deadline, address(0), BORROWER_AGENT_ID);
   183→
   184→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   185→        assertEq(loan.lender, address(0));
   186→    }
   187→
   188→    function test_createLoanZeroAmountReverts() public {
   189→        vm.prank(borrower);
   190→        vm.expectRevert(AgentMicrolending.ZeroAmount.selector);
   191→        lending.createLoanRequest(0, 100 * ONE_USDC, block.timestamp + 1 days, lender, BORROWER_AGENT_ID);
   192→    }
   193→
   194→    function test_createLoanRepayLessThanAmountReverts() public {
   195→        vm.prank(borrower);
   196→        vm.expectRevert(AgentMicrolending.RepayTooLow.selector);
   197→        lending.createLoanRequest(100 * ONE_USDC, 50 * ONE_USDC, block.timestamp + 1 days, lender, BORROWER_AGENT_ID);
   198→    }
   199→
   200→    function test_createLoanDeadlineInPastReverts() public {
   201→        vm.prank(borrower);
   202→        vm.expectRevert(AgentMicrolending.DeadlineInPast.selector);
   203→        lending.createLoanRequest(
   204→            100 * ONE_USDC, 110 * ONE_USDC, block.timestamp - 1, lender, BORROWER_AGENT_ID
   205→        );
   206→    }
   207→
   208→    function test_createMultipleLoans() public {
   209→        vm.startPrank(borrower);
   210→        uint256 id0 =
   211→            lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, BORROWER_AGENT_ID);
   212→        uint256 id1 = lending.createLoanRequest(
   213→            200 * ONE_USDC, 220 * ONE_USDC, block.timestamp + 60 days, address(0), BORROWER_AGENT_ID
   214→        );
   215→        vm.stopPrank();
   216→
   217→        assertEq(id0, 0);
   218→        assertEq(id1, 1);
   219→        assertEq(lending.totalLoans(), 2);
   220→    }
   221→
   222→    function test_borrowerLoansTracked() public {
   223→        vm.startPrank(borrower);
   224→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, BORROWER_AGENT_ID);
   225→        lending.createLoanRequest(
   226→            200 * ONE_USDC, 220 * ONE_USDC, block.timestamp + 60 days, address(0), BORROWER_AGENT_ID
   227→        );
   228→        vm.stopPrank();
   229→
   230→        uint256[] memory ids = lending.getBorrowerLoans(borrower);
   231→        assertEq(ids.length, 2);
   232→        assertEq(ids[0], 0);
   233→        assertEq(ids[1], 1);
   234→    }
   235→
   236→    // ════════════════════════════════════════════
   237→    //  Fund loan
   238→    // ════════════════════════════════════════════
   239→
   240→    function _createDefaultLoan() internal returns (uint256) {
   241→        vm.prank(borrower);
   242→        return lending.createLoanRequest(
   243→            100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, lender, BORROWER_AGENT_ID
   244→        );
   245→    }
   246→
   247→    function _createOpenLoan() internal returns (uint256) {
   248→        vm.prank(borrower);
   249→        return lending.createLoanRequest(
   250→            100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID
   251→        );
   252→    }
   253→
   254→    function test_fundLoan() public {
   255→        uint256 loanId = _createDefaultLoan();
   256→        uint256 borrowerBal = usdc.balanceOf(borrower);
   257→
   258→        vm.prank(lender);
   259→        lending.fundLoan(loanId);
   260→
   261→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   262→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Funded));
   263→        assertEq(loan.actualLender, lender);
   264→        assertTrue(loan.fundedAt > 0);
   265→        assertEq(usdc.balanceOf(borrower), borrowerBal + 100 * ONE_USDC);
   266→    }
   267→
   268→    function test_fundOpenLoan() public {
   269→        uint256 loanId = _createOpenLoan();
   270→
   271→        vm.prank(stranger);
   272→        lending.fundLoan(loanId);
   273→
   274→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   275→        assertEq(loan.actualLender, stranger);
   276→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Funded));
   277→    }
   278→
   279→    function test_fundLoanWrongLenderReverts() public {
   280→        uint256 loanId = _createDefaultLoan();
   281→
   282→        vm.prank(stranger);
   283→        vm.expectRevert(AgentMicrolending.NotAuthorizedLender.selector);
   284→        lending.fundLoan(loanId);
   285→    }
   286→
   287→    function test_fundLoanNotOpenReverts() public {
   288→        uint256 loanId = _createDefaultLoan();
   289→
   290→        vm.prank(lender);
   291→        lending.fundLoan(loanId);
   292→
   293→        vm.prank(lender);
   294→        vm.expectRevert(AgentMicrolending.LoanNotOpen.selector);
   295→        lending.fundLoan(loanId);
   296→    }
   297→
   298→    function test_fundLoanTracksLenderLoans() public {
   299→        uint256 loanId = _createDefaultLoan();
   300→
   301→        vm.prank(lender);
   302→        lending.fundLoan(loanId);
   303→
   304→        uint256[] memory ids = lending.getLenderLoans(lender);
   305→        assertEq(ids.length, 1);
   306→        assertEq(ids[0], loanId);
   307→    }
   308→
   309→    function test_fundLoanAfterDeadlineReverts() public {
   310→        uint256 loanId = _createDefaultLoan();
   311→
   312→        vm.warp(block.timestamp + 31 days);
   313→
   314→        vm.prank(lender);
   315→        vm.expectRevert(AgentMicrolending.DeadlineReached.selector);
   316→        lending.fundLoan(loanId);
   317→    }
   318→
   319→    // ════════════════════════════════════════════
   320→    //  Repay loan
   321→    // ════════════════════════════════════════════
   322→
   323→    function _createAndFundLoan() internal returns (uint256) {
   324→        uint256 loanId = _createDefaultLoan();
   325→        vm.prank(lender);
   326→        lending.fundLoan(loanId);
   327→        return loanId;
   328→    }
   329→
   330→    function test_repayLoan() public {
   331→        uint256 loanId = _createAndFundLoan();
   332→        uint256 lenderBal = usdc.balanceOf(lender);
   333→
   334→        vm.prank(borrower);
   335→        lending.repayLoan(loanId);
   336→
   337→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   338→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Repaid));
   339→        assertEq(usdc.balanceOf(lender), lenderBal + 110 * ONE_USDC);
   340→    }
   341→
   342→    function test_repayLoanNotBorrowerReverts() public {
   343→        uint256 loanId = _createAndFundLoan();
   344→
   345→        vm.prank(stranger);
   346→        vm.expectRevert(AgentMicrolending.NotBorrower.selector);
   347→        lending.repayLoan(loanId);
   348→    }
   349→
   350→    function test_repayLoanNotFundedReverts() public {
   351→        uint256 loanId = _createDefaultLoan();
   352→
   353→        vm.prank(borrower);
   354→        vm.expectRevert(AgentMicrolending.LoanNotFunded.selector);
   355→        lending.repayLoan(loanId);
   356→    }
   357→
   358→    function test_repayLoanAfterDeadlineReverts() public {
   359→        uint256 loanId = _createAndFundLoan();
   360→
   361→        vm.warp(block.timestamp + 31 days);
   362→
   363→        vm.prank(borrower);
   364→        vm.expectRevert(AgentMicrolending.DeadlineReached.selector);
   365→        lending.repayLoan(loanId);
   366→    }
   367→
   368→    // ════════════════════════════════════════════
   369→    //  Cancel loan request
   370→    // ════════════════════════════════════════════
   371→
   372→    function test_cancelLoanRequest() public {
   373→        uint256 loanId = _createDefaultLoan();
   374→
   375→        vm.prank(borrower);
   376→        lending.cancelLoanRequest(loanId);
   377→
   378→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   379→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Cancelled));
   380→    }
   381→
   382→    function test_cancelLoanNotBorrowerReverts() public {
   383→        uint256 loanId = _createDefaultLoan();
   384→
   385→        vm.prank(stranger);
   386→        vm.expectRevert(AgentMicrolending.NotBorrower.selector);
   387→        lending.cancelLoanRequest(loanId);
   388→    }
   389→
   390→    function test_cancelLoanNotOpenReverts() public {
   391→        uint256 loanId = _createAndFundLoan();
   392→
   393→        vm.prank(borrower);
   394→        vm.expectRevert(AgentMicrolending.LoanNotOpen.selector);
   395→        lending.cancelLoanRequest(loanId);
   396→    }
   397→
   398→    // ════════════════════════════════════════════
   399→    //  Claim defaulted
   400→    // ════════════════════════════════════════════
   401→
   402→    function test_claimDefaulted() public {
   403→        uint256 loanId = _createAndFundLoan();
   404→
   405→        vm.warp(block.timestamp + 31 days);
   406→
   407→        vm.prank(lender);
   408→        lending.claimDefaulted(loanId);
   409→
   410→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   411→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Defaulted));
   412→    }
   413→
   414→    function test_claimDefaultedBeforeDeadlineReverts() public {
   415→        uint256 loanId = _createAndFundLoan();
   416→
   417→        vm.prank(lender);
   418→        vm.expectRevert(AgentMicrolending.DeadlineNotReached.selector);
   419→        lending.claimDefaulted(loanId);
   420→    }
   421→
   422→    function test_claimDefaultedNotFundedReverts() public {
   423→        uint256 loanId = _createDefaultLoan();
   424→
   425→        vm.warp(block.timestamp + 31 days);
   426→
   427→        vm.prank(lender);
   428→        vm.expectRevert(AgentMicrolending.LoanNotFunded.selector);
   429→        lending.claimDefaulted(loanId);
   430→    }
   431→
   432→    function test_claimDefaultedAnyoneCanCall() public {
   433→        uint256 loanId = _createAndFundLoan();
   434→
   435→        vm.warp(block.timestamp + 31 days);
   436→
   437→        vm.prank(stranger);
   438→        lending.claimDefaulted(loanId);
   439→
   440→        AgentMicrolending.LoanRequest memory loan = lending.getLoan(loanId);
   441→        assertEq(uint8(loan.status), uint8(AgentMicrolending.LoanStatus.Defaulted));
   442→    }
   443→
   444→    // ════════════════════════════════════════════
   445→    //  Advanced view functions
   446→    // ════════════════════════════════════════════
   447→
   448→    function test_getOpenLoans() public {
   449→        // Create 3 loans, fund one
   450→        vm.startPrank(borrower);
   451→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   452→        lending.createLoanRequest(200 * ONE_USDC, 220 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   453→        lending.createLoanRequest(300 * ONE_USDC, 330 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   454→        vm.stopPrank();
   455→
   456→        // Fund loan 1
   457→        vm.prank(lender);
   458→        lending.fundLoan(1);
   459→
   460→        AgentMicrolending.LoanRequest[] memory openLoans = lending.getOpenLoans(0, 10);
   461→        assertEq(openLoans.length, 2);
   462→        assertEq(openLoans[0].id, 0);
   463→        assertEq(openLoans[1].id, 2);
   464→    }
   465→
   466→    function test_getOpenLoansPagination() public {
   467→        // Create 5 open loans
   468→        vm.startPrank(borrower);
   469→        for (uint256 i = 0; i < 5; i++) {
   470→            lending.createLoanRequest(
   471→                100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID
   472→            );
   473→        }
   474→        vm.stopPrank();
   475→
   476→        AgentMicrolending.LoanRequest[] memory page1 = lending.getOpenLoans(0, 2);
   477→        assertEq(page1.length, 2);
   478→        assertEq(page1[0].id, 0);
   479→        assertEq(page1[1].id, 1);
   480→
   481→        AgentMicrolending.LoanRequest[] memory page2 = lending.getOpenLoans(2, 2);
   482→        assertEq(page2.length, 2);
   483→        assertEq(page2[0].id, 2);
   484→        assertEq(page2[1].id, 3);
   485→    }
   486→
   487→    function test_getBorrowerOpenLoans() public {
   488→        vm.startPrank(borrower);
   489→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   490→        lending.createLoanRequest(200 * ONE_USDC, 220 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   491→        vm.stopPrank();
   492→
   493→        // Fund one
   494→        vm.prank(lender);
   495→        lending.fundLoan(0);
   496→
   497→        AgentMicrolending.LoanRequest[] memory openLoans = lending.getBorrowerOpenLoans(borrower);
   498→        assertEq(openLoans.length, 1);
   499→        assertEq(openLoans[0].id, 1);
   500→    }
   501→
   502→    function test_getLenderActiveLoanIds() public {
   503→        // Create and fund two loans
   504→        vm.prank(borrower);
   505→        lending.createLoanRequest(100 * ONE_USDC, 110 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   506→        vm.prank(borrower);
   507→        lending.createLoanRequest(200 * ONE_USDC, 220 * ONE_USDC, block.timestamp + 30 days, address(0), BORROWER_AGENT_ID);
   508→
   509→        vm.prank(lender);
   510→        lending.fundLoan(0);
   511→        vm.prank(lender);
   512→        lending.fundLoan(1);
   513→
   514→        // Repay one
   515→        vm.prank(borrower);
   516→        lending.repayLoan(0);
   517→
   518→        uint256[] memory activeIds = lending.getLenderActiveLoanIds(lender);
   519→        assertEq(activeIds.length, 1);
   520→        assertEq(activeIds[0], 1);
   521→    }
   522→
   523→    function test_totalLoansEmpty() public view {
   524→        assertEq(lending.totalLoans(), 0);
   525→    }
   526→
   527→    // ════════════════════════════════════════════
   528→    //  Integration — full lifecycle
   529→    // ════════════════════════════════════════════
   530→
   531→    function test_fullLoanLifecycle() public {
   532→        // 1. Borrower creates loan request
