        uint256 balance = sbt.balanceOf(ADDR_1, SBT_TOKEN_ID);
        emit log_named_address("Address 1", ADDR_1);
        emit log_named_uint("SBT 8004 Balance (direct)", balance);
        emit log_named_string("Holds SBT directly", balance > 0 ? "YES" : "NO");
    }

    function test_addr1_usdcBalance() public view {
        uint256 balance = usdc.balanceOf(ADDR_1);
        emit log_named_address("Address 1", ADDR_1);
        emit log_named_uint("USDC Balance (raw)", balance);
        emit log_named_uint("USDC Balance (human-readable, 6 decimals)", balance / 1e6);
    }

    function test_addr1_createLoan() public {
        emit log_named_address("Address 1", ADDR_1);

        if (!addr1Found) {
            emit log_string("RESULT: No agent ID found for Address 1 - CANNOT create loan");
            emit log_string("This address is NOT registered in the Self Agent Registry");
            return;
        }

        bool humanProof = registry.hasHumanProof(addr1AgentId);
        emit log_named_uint("Agent ID", addr1AgentId);
        emit log_named_string("Human Proof", humanProof ? "YES" : "NO");

