    function _checkSbtBalance(address account) internal view returns (uint256 balance, string memory method) {
        // Try ERC-1155 balanceOf(address,uint256) first
        try IERC1155(SELF_SBT).balanceOf(account, SBT_TOKEN_ID) returns (uint256 bal) {
            return (bal, "ERC-1155");
        } catch {}

        // Try ERC-721 balanceOf(address)
        try IERC721(SELF_SBT).balanceOf(account) returns (uint256 bal) {
            return (bal, "ERC-721");
        } catch {}

        return (0, "UNREACHABLE");
    }

