     1→import { createPublicClient, http, encodeFunctionData } from "viem";
     2→import { entryPoint08Address, getUserOperationHash } from "viem/account-abstraction";
     3→import { celo } from "viem/chains";
     4→import { PrivyClient } from "@privy-io/node";
     5→import { createViemAccount } from "@privy-io/node/viem";
     6→
     7→const CELO_RPC_URL = process.env.CELO_RPC_URL || "https://forno.celo.org";
     8→const CANDIDE_API_KEY = process.env.CANDIDE_API_KEY || "";
     9→const CANDIDE_URL = CANDIDE_API_KEY
    10→  ? `https://api.candide.dev/api/v3/42220/${CANDIDE_API_KEY}`
    11→  : "https://api.candide.dev/public/v3/42220";
    12→const SPONSORSHIP_POLICY_ID = process.env.CANDIDE_SPONSORSHIP_POLICY_ID || "";
    13→
    14→// SimpleAccount v0.8 implementation (deployed on Celo, works with EP v0.8 + 7702)
    15→const SIMPLE_ACCOUNT_IMPL = "0xe6Cae83BdE06E4c305530e199D7217f42808555B" as const;
    16→
    17→// SimpleAccount.execute(address dest, uint256 value, bytes calldata func)
    18→const EXECUTE_ABI = [{
    19→  name: "execute",
    20→  type: "function",
    21→  inputs: [
    22→    { name: "dest", type: "address" },
    23→    { name: "value", type: "uint256" },
    24→    { name: "func", type: "bytes" },
    25→  ],
    26→  outputs: [],
    27→}] as const;
    28→
    29→function log(level: "info" | "warn" | "error", msg: string, meta?: Record<string, unknown>) {
    30→  const entry = { ts: new Date().toISOString(), level, component: "smart-account", msg, ...meta };
    31→  if (level === "error") console.error(JSON.stringify(entry));
    32→  else console.log(JSON.stringify(entry));
    33→}
    34→
    35→const h = (v: bigint | number) => "0x" + BigInt(v).toString(16);
    36→
    37→function getPrivyClient() {
    38→  const appId = process.env.PRIVY_APP_ID;
    39→  const appSecret = process.env.PRIVY_APP_SECRET;
    40→  if (!appId || !appSecret) throw new Error("PRIVY_APP_ID and PRIVY_APP_SECRET must be set");
    41→  return new PrivyClient({ appId, appSecret });
    42→}
    43→
    44→async function candideRpc(method: string, params: any[]) {
    45→  const res = await fetch(CANDIDE_URL, {
    46→    method: "POST",
    47→    headers: { "Content-Type": "application/json" },
    48→    body: JSON.stringify({ jsonrpc: "2.0", method, params, id: Date.now() }),
    49→  });
    50→  const data = await res.json();
    51→  if (data.error) throw new Error(`${method}: ${data.error.message}`);
    52→  return data.result;
    53→}
    54→
    55→/**
    56→ * Send a gasless EIP-7702 UserOperation via Candide on Celo.
    57→ *
    58→ * Flow:
    59→ * 1. Sign 7702 authorization (Privy EOA → SimpleAccount delegation)
    60→ * 2. Build UserOp with callData
    61→ * 3. Get Candide sponsorship (pm_sponsorUserOperation)
    62→ * 4. Sign UserOp hash with raw secp256k1 (no EIP-191 prefix)
    63→ * 5. Submit via eth_sendUserOperation
    64→ *
    65→ * The Privy EOA address IS the smart account address (7702).
    66→ */
    67→async function sendUserOp(
    68→  walletId: string,
    69→  walletAddress: `0x${string}`,
    70→  callData: `0x${string}`,
    71→) {
    72→  const privy = getPrivyClient();
    73→  const account = await createViemAccount(privy, { walletId, address: walletAddress });
    74→  const publicClient = createPublicClient({ chain: celo, transport: http(CELO_RPC_URL) });
    75→
    76→  // 1. Sign 7702 authorization
    77→  const txNonce = await publicClient.getTransactionCount({ address: walletAddress });
    78→  const auth = await account.signAuthorization!({
    79→    address: SIMPLE_ACCOUNT_IMPL,
    80→    chainId: celo.id,
    81→    nonce: txNonce,
    82→  }) as any;
    83→
    84→  const eip7702Auth = {
    85→    chainId: h(auth.chainId),
    86→    address: auth.address,
    87→    nonce: h(auth.nonce),
    88→    yParity: h(auth.yParity),
    89→    r: auth.r,
    90→    s: auth.s,
    91→  };
    92→
    93→  // 2. Build base UserOp
    94→  const epNonce = await publicClient.readContract({
    95→    address: entryPoint08Address,
    96→    abi: [{ name: "getNonce", type: "function", stateMutability: "view", inputs: [{ name: "sender", type: "address" }, { name: "key", type: "uint192" }], outputs: [{ name: "", type: "uint256" }] }],
    97→    functionName: "getNonce",
    98→    args: [walletAddress, BigInt(0)],
    99→  });
   100→
   101→  const block = await publicClient.getBlock();
   102→  const baseFee = block.baseFeePerGas ?? BigInt(5000000000);
   103→  const dummySig = await account.signMessage({ message: "7702-estimation" });
   104→
   105→  const userOp: any = {
   106→    sender: walletAddress,
   107→    nonce: h(epNonce),
   108→    callData,
   109→    callGasLimit: h(100000),
   110→    verificationGasLimit: h(500000),
   111→    preVerificationGas: h(100000),
   112→    maxFeePerGas: h(baseFee * BigInt(2)),
   113→    maxPriorityFeePerGas: h(baseFee / BigInt(5)),
   114→    signature: dummySig,
   115→    eip7702Auth,
   116→  };
   117→
   118→  // 3. Get Candide sponsorship
   119→  const sponsor = await candideRpc("pm_sponsorUserOperation", [
   120→    userOp, entryPoint08Address, { sponsorshipPolicyId: SPONSORSHIP_POLICY_ID },
   121→  ]);
   122→
   123→  userOp.paymaster = sponsor.paymaster;
   124→  userOp.paymasterData = sponsor.paymasterData;
   125→  userOp.paymasterVerificationGasLimit = sponsor.paymasterVerificationGasLimit;
   126→  userOp.paymasterPostOpGasLimit = sponsor.paymasterPostOpGasLimit;
   127→  if (sponsor.callGasLimit) userOp.callGasLimit = sponsor.callGasLimit;
   128→  if (sponsor.verificationGasLimit) userOp.verificationGasLimit = sponsor.verificationGasLimit;
   129→  if (sponsor.preVerificationGas) userOp.preVerificationGas = sponsor.preVerificationGas;
   130→  if (sponsor.maxFeePerGas) userOp.maxFeePerGas = sponsor.maxFeePerGas;
   131→  if (sponsor.maxPriorityFeePerGas) userOp.maxPriorityFeePerGas = sponsor.maxPriorityFeePerGas;
   132→
   133→  // 4. Compute hash and sign with raw secp256k1 (SimpleAccount uses raw ECDSA)
   134→  const opHash = getUserOperationHash({
   135→    userOperation: {
   136→      sender: walletAddress,
   137→      nonce: BigInt(userOp.nonce),
   138→      callData: userOp.callData,
   139→      callGasLimit: BigInt(userOp.callGasLimit),
   140→      verificationGasLimit: BigInt(userOp.verificationGasLimit),
   141→      preVerificationGas: BigInt(userOp.preVerificationGas),
   142→      maxFeePerGas: BigInt(userOp.maxFeePerGas),
   143→      maxPriorityFeePerGas: BigInt(userOp.maxPriorityFeePerGas),
   144→      paymaster: userOp.paymaster,
   145→      paymasterData: userOp.paymasterData || "0x",
   146→      paymasterVerificationGasLimit: BigInt(userOp.paymasterVerificationGasLimit || "0x0"),
   147→      paymasterPostOpGasLimit: BigInt(userOp.paymasterPostOpGasLimit || "0x0"),
   148→      signature: "0x",
   149→    },
   150→    entryPointAddress: entryPoint08Address,
   151→    entryPointVersion: "0.8",
   152→    chainId: celo.id,
   153→  });
   154→
   155→  const rawSig = await privy.wallets().ethereum().signSecp256k1(walletId, {
   156→    params: { hash: opHash },
   157→  });
   158→  userOp.signature = (rawSig as any).signature;
   159→
   160→  // 5. Send
   161→  const userOpHash = await candideRpc("eth_sendUserOperation", [userOp, entryPoint08Address]);
   162→  return userOpHash;
   163→}
   164→
   165→/**
   166→ * Send a gasless contract call via EIP-7702 on Celo.
   167→ * The agent never pays gas — Candide sponsors the UserOperation.
   168→ */
   169→export async function sendGaslessContractCall(
   170→  walletId: string,
   171→  walletAddress: string,
   172→  to: `0x${string}`,
   173→  data: `0x${string}`,
   174→  value?: bigint
   175→) {
